import React, { useState } from 'react';
import { 
  FaComments, 
  FaUsers, 
  FaGlobe, 
  FaSearch, 
  FaPhone, 
  FaVideo, 
  FaEllipsisH, 
  FaPaperclip, 
  FaLink, 
  FaImage, 
  FaMicrophone, 
  FaCamera, 
  FaPaperPlane, 
  FaSignOutAlt, 
  FaClipboardList, 
  FaFolder, 
  FaChartBar, 
  FaMapMarkerAlt,
  FaCog
} from 'react-icons/fa';
import './App.css';

function App() {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showChat, setShowChat] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [messages, setMessages] = useState([
    { id: 1, text: "Hello! I'm your AI assistant. How can I help you today?", isBot: true, timestamp: new Date() }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [settings, setSettings] = useState({
    notifications: {
      emailNotifications: true,
      pushNotifications: false,
      soundAlerts: true,
      desktopNotifications: false
    },
    appearance: {
      darkMode: true,
      compactMode: false,
      showAvatars: true,
      showTimestamps: true
    },
    privacy: {
      showOnlineStatus: true,
      allowDirectMessages: true,
      showLastSeen: false,
      profileVisibility: 'public'
    },
    security: {
      twoFactorAuth: false,
      sessionTimeout: 30,
      loginNotifications: true
    }
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prevState => ({
      ...prevState,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Login attempt:', formData);
    // Simulate successful login and show chat
    setShowChat(true);
  };

  const handleSendMessage = (e) => {
    e.preventDefault();
    if (inputMessage.trim()) {
      const newMessage = {
        id: messages.length + 1,
        text: inputMessage,
        isBot: false,
        timestamp: new Date()
      };
      setMessages([...messages, newMessage]);
      setInputMessage('');

      // Simulate bot response
      setTimeout(() => {
        const botResponse = {
          id: messages.length + 2,
          text: "I understand you said: " + inputMessage + ". This is a demo response. In a real application, this would be processed by an LLM model.",
          isBot: true,
          timestamp: new Date()
        };
        setMessages(prev => [...prev, botResponse]);
      }, 1000);
    }
  };

  const toggleSetting = (category, setting) => {
    setSettings(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [setting]: !prev[category][setting]
      }
    }));
  };

  const updateSetting = (category, setting, value) => {
    setSettings(prev => ({
      ...prev,
      [category]: {
        ...prev[category],
        [setting]: value
      }
    }));
  };

  if (showChat) {
    return (
      <div className="chat-app">
        {/* Left Sidebar */}
        <div className="chat-sidebar">
          <div className="sidebar-header">
            <div className="logo-section">
              <img 
                src={process.env.PUBLIC_URL + '/quadrant-logo.png'} 
                alt="Company Logo" 
                className="company-logo"
                onError={(e) => {
                  e.target.style.display = 'none';
                }}
              />
              <span className="logo-text">Quadra</span>
            </div>
          </div>

          <div className="sidebar-menu">
            <div className="menu-item active">
              <span className="menu-icon"><FaComments /></span>
              <span>Direct</span>
            </div>
            <div className="menu-item">
              <span className="menu-icon"><FaUsers /></span>
              <span>Group</span>
            </div>
            <div className="menu-item">
              <span className="menu-icon"><FaGlobe /></span>
              <span>Public</span>
            </div>
          </div>

          <div className="search-section">
            <div className="search-container">
              <span className="search-icon"><FaSearch /></span>
              <input type="text" placeholder="Search chats..." className="search-input" />
            </div>
          </div>

          <div className="chat-list">
            <div className="chat-item active">
              <div className="chat-avatar">T</div>
              <div className="chat-info">
                <div className="chat-name">Theron Trump</div>
                <div className="chat-preview">Last seen 10:30pm ago</div>
              </div>
            </div>
            <div className="chat-item">
              <div className="chat-avatar">M</div>
              <div className="chat-info">
                <div className="chat-name">Mical Clark</div>
                <div className="chat-preview">Nullam facilisis velit.</div>
              </div>
            </div>
            <div className="chat-item">
              <div className="chat-avatar">C</div>
              <div className="chat-info">
                <div className="chat-name">Colin Nathan</div>
                <div className="chat-preview">Nullam facilisis velit.</div>
              </div>
            </div>
          </div>

          <div className="user-profile">
            <div className="user-avatar">D</div>
            <div className="user-info">
              <div className="user-name">Dhanshika</div>
              <div className="user-status">Admin</div>
            </div>
            <button className="settings-btn">
              <FaCog />
            </button>
          </div>
        </div>

        {/* Main Chat Area */}
        <div className="chat-main">
          <div className="chat-header">
            <div className="chat-partner">
              <div className="partner-avatar">T</div>
              <div className="partner-info">
                <div className="partner-name">Theron Trump</div>
                <div className="partner-status">Last seen 10:30pm ago</div>
              </div>
            </div>
            <div className="header-actions">
              <button className="action-btn"><FaEllipsisH /></button>
            </div>
          </div>

          <div className="chat-messages">
            {messages.map((message) => (
              <div key={message.id} className={`message ${message.isBot ? 'bot' : 'user'}`}>
                <div className="message-avatar">
                  {message.isBot ? 'AI' : 'U'}
                </div>
                <div className="message-content">
                  <div className="message-text">{message.text}</div>
                  <div className="message-time">
                    {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="chat-input-container">
            <form onSubmit={handleSendMessage} className="chat-input-form">
              <div className="input-actions">
                <button type="button" className="action-button"><FaPaperclip /></button>
                <button type="button" className="action-button"><FaLink /></button>
                <button type="button" className="action-button"><FaImage /></button>
                <button type="button" className="action-button"><FaMicrophone /></button>
                <button type="button" className="action-button"><FaCamera /></button>
              </div>
              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Say something..."
                className="chat-input"
              />
              <button type="submit" className="send-button">
                <FaPaperPlane />
              </button>
            </form>
          </div>
        </div>

        {/* Right Sidebar */}
        <div className="chat-right-sidebar">
          <div className="sidebar-section">
            <h3 className="section-title">Quick Actions</h3>
            <div className="quick-actions-list">
              <div className="quick-action-item">
                <span className="action-icon"><FaSignOutAlt /></span>
                <span className="action-text">Take me to portal</span>
              </div>
              <div className="quick-action-item">
                <span className="action-icon"><FaClipboardList /></span>
                <span className="action-text">Current projects</span>
              </div>
              <div className="quick-action-item">
                <span className="action-icon"><FaFolder /></span>
                <span className="action-text">Projects archive</span>
              </div>
              <div className="quick-action-item">
                <span className="action-icon"><FaChartBar /></span>
                <span className="action-text">Dashboard</span>
              </div>
            </div>
          </div>

          <div className="floating-actions">
            <button className="floating-btn"><FaFolder /></button>
            <button className="floating-btn"><FaMapMarkerAlt /></button>
            <button className="floating-btn"><FaCamera /></button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="App">
      <div className="login-container">
        <div className="login-card">
          <div className="welcome-section">
            <h1 className="welcome-title">Welcome back</h1>
            <p className="welcome-subtitle">Sign in to continue to your portal</p>
          </div>

          <form className="login-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label htmlFor="email" className="form-label">Email</label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                className="form-input"
                placeholder="Enter your email"
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="password" className="form-label">Password</label>
              <input
                type="password"
                id="password"
                name="password"
                value={formData.password}
                onChange={handleInputChange}
                className="form-input"
                placeholder="Enter your password"
                required
              />
            </div>

            <div className="form-options">
              <label className="checkbox-container">
                <input type="checkbox" className="checkbox" />
                <span className="checkmark"></span>
                Remember me
              </label>
              <a href="#" className="forgot-password">Forgot password?</a>
            </div>

            <button type="submit" className="login-button">
              Sign In
            </button>
          </form>

          <div className="signup-section">
            <p className="signup-text">
              Don't have an account? <a href="#" className="signup-link">Sign up</a>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
